    { day: "Mon", workout: true, category: "Strength", minutes: 45, sets: "4", reps: "8-10", cardio: 10, note: "Upper body push" },
    { day: "Tue", workout: true, category: "Cardio", minutes: 30, sets: "", reps: "", cardio: 30, note: "Easy run + mobility" },
    { day: "Wed", workout: false, category: "Recovery", minutes: 0, sets: "", reps: "", cardio: 0, note: "Rest and stretch" },
    { day: "Thu", workout: true, category: "Strength", minutes: 50, sets: "5", reps: "5", cardio: 8, note: "Lower body focus" },
    { day: "Fri", workout: true, category: "Core", minutes: 25, sets: "3", reps: "12", cardio: 12, note: "Abs + incline walk" },
    { day: "Sat", workout: false, category: "Recovery", minutes: 0, sets: "", reps: "", cardio: 0, note: "Optional yoga" },
    { day: "Sun", workout: true, category: "Mixed", minutes: 60, sets: "4", reps: "10", cardio: 20, note: "Full-body circuit" },
  ];

  const [week, setWeek] = useState(initialDays);
  const [goal, setGoal] = useState("Build consistency");
  const [focus, setFocus] = useState("Strength + Cardio");
  const [weeklyNote, setWeeklyNote] = useState("Small wins count. Keep showing up.");
  const [selectedDay, setSelectedDay] = useState(null);

  const stats = useMemo(() => {
    const workoutDays = week.filter((d) => d.workout).length;
    const totalMinutes = week.reduce((sum, d) => sum + Number(d.minutes || 0), 0);
    const cardioMinutes = week.reduce((sum, d) => sum + Number(d.cardio || 0), 0);
    const totalSets = week.reduce((sum, d) => sum + Number(d.sets || 0), 0);
    const progress = Math.round((workoutDays / 7) * 100);
    return { workoutDays, totalMinutes, cardioMinutes, totalSets, progress };
  }, [week]);

  const categoryCounts = useMemo(() => {
    const counts = {};
    week.forEach((d) => {
      if (d.workout) counts[d.category] = (counts[d.category] || 0) + 1;
    });
    return counts;
  }, [week]);

  const toggleWorkout = (index) => {
    setWeek((prev) =>
      prev.map((d, i) =>
        i === index
          ? {
              ...d,
              workout: !d.workout,
              minutes: !d.workout ? d.minutes || 30 : 0,
              cardio: !d.workout ? d.cardio || 10 : 0,
            }
          : d
      )
    );
