  const updateDay = (index, field, value) => {
    setWeek((prev) => prev.map((d, i) => (i === index ? { ...d, [field]: value } : d)));
  };

  const categories = ["Strength", "Cardio", "Core", "Mixed", "Recovery"];

  return (
    <div className="w-full h-full p-4 sm:p-6 bg-gradient-to-br from-slate-950 via-slate-900 to-emerald-950 text-slate-50 overflow-hidden">
