              <div>
                <div className="inline-flex items-center gap-2 rounded-full border border-emerald-400/20 bg-emerald-400/10 px-3 py-1 text-xs font-semibold tracking-wide text-emerald-200">
                  <span className="animate-pulse">🏃</span>
                  Weekly Fitness Flow
                </div>
                <h2 className="mt-3 text-2xl sm:text-3xl font-bold tracking-tight">
                  Track your week with calm momentum
                </h2>
                <p className="mt-2 text-sm text-slate-300 max-w-2xl">
                  Build a repeatable rhythm for workouts, sets, reps, cardio minutes, and notes.
                </p>
              </div>

              <div className="hidden sm:flex flex-col items-end gap-2 rounded-2xl border border-white/10 bg-black/20 px-4 py-3 min-w-[170px]">
                <div className="text-xs uppercase tracking-[0.2em] text-slate-400">Weekly vibe</div>
                <div className="text-lg font-semibold text-emerald-200">💪 Consistent</div>
                <div className="text-xs text-slate-300">Progress over perfection</div>
