                        type="number"
                        min="0"
                        value={d.cardio}
                        onChange={(e) => updateDay(i, "cardio", e.target.value)}
                        className="rounded-xl border border-white/10 bg-slate-950/60 px-2 py-2 text-xs text-slate-100 outline-none"
