                  />
                </div>
                <div className="mt-3 flex items-center justify-between text-xs text-slate-400">
                  <span>Mon</span>
                  <span>Wed</span>
                  <span>Fri</span>
                  <span>Sun</span>
                </div>

                <div className="mt-5 grid grid-cols-7 gap-2">
                  {week.map((d, i) => (
                    <button
                      key={d.day}
                      onClick={() => setSelectedDay(i)}
                      className={`group relative rounded-2xl border px-2 py-3 text-center transition-all duration-300 hover:-translate-y-0.5 ${
                        d.workout
                          ? "border-emerald-400/30 bg-emerald-400/10"
                          : "border-white/10 bg-white/5"
                      } ${selectedDay === i ? "ring-2 ring-emerald-300/40" : ""}`}
                    >
                      <div className="text-[11px] font-medium text-slate-300">{d.day}</div>
                      <div className={`mt-1 text-lg ${d.workout ? "animate-bounce" : "opacity-60"}`}>
                        {d.workout ? "🔥" : "🫧"}
                      </div>
                      <div className="mt-1 text-[10px] text-slate-400 leading-tight">
                        {d.workout ? `${d.minutes}m` : "rest"}
                      </div>
                      <div className="absolute inset-0 rounded-2xl bg-white/0 group-hover:bg-white/5 transition-colors" />
                    </button>
                  ))}
                </div>
              </div>

              <div className="rounded-3xl border border-white/10 bg-slate-950/40 p-4 sm:p-5">
                <h3 className="text-sm font-semibold text-slate-100">Category mix</h3>
                <p className="text-xs text-slate-400 mb-4">What your week is made of</p>
                <div className="space-y-3">
                  {categories.map((cat, idx) => {
                    const value = categoryCounts[cat] || 0;
                    const pct = Math.max(10, (value / Math.max(stats.workoutDays, 1)) * 100);
                    const colors = [
                      "from-emerald-400 to-teal-300",
                      "from-sky-400 to-cyan-300",
                      "from-fuchsia-400 to-pink-300",
                      "from-amber-400 to-orange-300",
                      "from-violet-400 to-indigo-300",
                    ];
                    return (
                      <div key={cat}>
                        <div className="flex items-center justify-between text-xs mb-1">
                          <span className="text-slate-300">{cat}</span>
                          <span className="text-slate-400">{value} sessions</span>
                        </div>
                        <div className="h-2 rounded-full bg-white/10 overflow-hidden">
                          <div
                            className={`h-full rounded-full bg-gradient-to-r ${colors[idx % colors.length]} transition-all duration-700`}
                            style={{ width: `${pct}%` }}
                          />
                        </div>
                      </div>
                    );
                  })}
                </div>
                <div className="mt-5 rounded-2xl border border-white/10 bg-white/5 p-3">
                  <div className="text-xs uppercase tracking-[0.2em] text-slate-400">Goal</div>
                  <input
                    value={goal}
                    onChange={(e) => setGoal(e.target.value)}
                    className="mt-2 w-full bg-transparent text-sm outline-none text-slate-100 placeholder:text-slate-500"
                    placeholder="What are you training for?"
                  />
                  <div className="mt-3 text-xs text-slate-400">Focus</div>
                  <input
                    value={focus}
                    onChange={(e) => setFocus(e.target.value)}
                    className="mt-2 w-full bg-transparent text-sm outline-none text-slate-100 placeholder:text-slate-500"
                    placeholder="Strength, cardio, mobility..."
                  />
                </div>
              </div>
            </div>

            <div className="rounded-3xl border border-white/10 bg-slate-950/40 p-4 sm:p-5 flex-1 min-h-0">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h3 className="text-sm font-semibold text-slate-100">Weekly tracker</h3>
                  <p className="text-xs text-slate-400">Tap a day to edit and keep your rhythm alive</p>
                </div>
                <div className="text-xs text-slate-300">📋 Reusable template</div>
              </div>

              <div className="overflow-auto max-h-[42vh] pr-1">
                <div className="grid grid-cols-[72px_92px_90px_78px_72px_72px_1fr_72px] gap-2 min-w-[860px] text-xs text-slate-300 pb-2 border-b border-white/10">
                  <div>Day</div>
                  <div>Workout</div>
                  <div>Category</div>
                  <div>Minutes</div>
                  <div>Sets</div>
                  <div>Reps</div>
                  <div>Notes</div>
                  <div>Cardio</div>
                </div>

                <div className="space-y-2 mt-2">
                  {week.map((d, i) => (
                    <div
                      key={d.day}
                      className={`grid grid-cols-[72px_92px_90px_78px_72px_72px_1fr_72px] gap-2 min-w-[860px] items-center rounded-2xl border px-2 py-2 transition-all duration-300 ${
                        selectedDay === i ? "border-emerald-300/40 bg-emerald-400/10" : "border-white/10 bg-white/5"
                      }`}
                    >
                      <div className="font-semibold text-slate-100">{d.day}</div>
                      <button
                        onClick={() => toggleWorkout(i)}
                        className={`rounded-xl px-3 py-2 text-xs font-semibold transition-all duration-300 ${
                          d.workout
                            ? "bg-emerald-400/20 text-emerald-200 hover:bg-emerald-400/30"
                            : "bg-white/10 text-slate-300 hover:bg-white/15"
                        }`}
                      >
                        {d.workout ? "Active ✓" : "Rest"}
                      </button>
                      <select
                        value={d.category}
                        onChange={(e) => updateDay(i, "category", e.target.value)}
                        className="rounded-xl border border-white/10 bg-slate-950/60 px-2 py-2 text-xs text-slate-100 outline-none"
                      >
                        {categories.map((cat) => (
                          <option key={cat} value={cat}>
                            {cat}
                          </option>
                        ))}
                      </select>
                      <input
                        type="number"
                        min="0"
                        value={d.minutes}
                        onChange={(e) => updateDay(i, "minutes", e.target.value)}
                        className="rounded-xl border border-white/10 bg-slate-950/60 px-2 py-2 text-xs text-slate-100 outline-none"
                      />
                      <input
                        type="text"
                        value={d.sets}
                        onChange={(e) => updateDay(i, "sets", e.target.value)}
                        className="rounded-xl border border-white/10 bg-slate-950/60 px-2 py-2 text-xs text-slate-100 outline-none"
                        placeholder="—"
                      />
                      <input
                        type="text"
                        value={d.reps}
                        onChange={(e) => updateDay(i, "reps", e.target.value)}
                        className="rounded-xl border border-white/10 bg-slate-950/60 px-2 py-2 text-xs text-slate-100 outline-none"
                        placeholder="—"
                      />
                      <input
                        type="text"
                        value={d.note}
                        onChange={(e) => updateDay(i, "note", e.target.value)}
                        className="rounded-xl border border-white/10 bg-slate-950/60 px-3 py-2 text-xs text-slate-100 outline-none placeholder:text-slate-500"
                        placeholder="Quick note..."
                      />
                      <input
                        type="number"
                        min="0"
                        value={d.cardio}
                        onChange={(e) => updateDay(i, "cardio", e.target.value)}
                        className="rounded-xl border border-white/10 bg-slate-950/60 px-2 py-2 text-xs text-slate-100 outline-none"
                      />
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="p-5 sm:p-6 lg:p-7 border-t xl:border-t-0 xl:border-l border-white/10 bg-gradient-to-b from-white/5 to-transparent flex flex-col gap-5">
            <div className="rounded-3xl border border-emerald-400/20 bg-emerald-400/10 p-5">
              <div className="flex items-center gap-3">
                <div className="text-3xl animate-pulse">✨</div>
                <div>
                  <h3 className="font-semibold text-emerald-100">Your weekly intention</h3>
                  <p className="text-xs text-emerald-200/80">The reason behind the reps</p>
                </div>
              </div>
              <textarea
                value={weeklyNote}
                onChange={(e) => setWeeklyNote(e.target.value)}
                className="mt-4 w-full min-h-[120px] rounded-2xl border border-white/10 bg-slate-950/60 p-4 text-sm text-slate-100 outline-none placeholder:text-slate-500 resize-none"
                placeholder="Write a motivating note for the week..."
              />
              <div className="mt-3 flex flex-wrap gap-2 text-xs">
                {["Show up", "Recover well", "Stay steady", "Breathe", "Progress"].map((tag) => (
                  <button
                    key={tag}
                    onClick={() => setWeeklyNote((prev) => `${prev}${prev ? " • " : ""}${tag}`)}
                    className="rounded-full border border-white/10 bg-white/5 px-3 py-1 text-slate-200 hover:bg-white/10 transition-colors"
                  >
                    + {tag}
                  </button>
                ))}
              </div>
            </div>

            <div className="rounded-3xl border border-white/10 bg-slate-950/40 p-5">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="font-semibold text-slate-100">Day detail</h3>
                  <p className="text-xs text-slate-400">Select a day to preview the mood</p>
                </div>
                <div className="text-xl">{selectedDay !== null ? (week[selectedDay]?.workout ? "💥" : "🌿") : "🎯"}</div>
              </div>

              <div className="mt-4 rounded-2xl border border-white/10 bg-white/5 p-4 min-h-[170px]">
                {selectedDay !== null ? (
                  <div className="space-y-3">
                    <div className="flex items-center justify-between">
                      <div className="text-lg font-semibold text-slate-100">{week[selectedDay].day}</div>
                      <div className="text-xs rounded-full px-2 py-1 bg-black/20 text-slate-300">
                        {week[selectedDay].workout ? "Training" : "Recovery"}
                      </div>
                    </div>
                    <div className="text-sm text-slate-300">
                      <span className="text-slate-400">Category:</span> {week[selectedDay].category}
                    </div>
                    <div className="text-sm text-slate-300">
                      <span className="text-slate-400">Duration:</span> {week[selectedDay].minutes} min
                    </div>
                    <div className="text-sm text-slate-300">
                      <span className="text-slate-400">Sets/Reps:</span>{" "}
                      {week[selectedDay].sets || "—"} / {week[selectedDay].reps || "—"}
                    </div>
                    <div className="text-sm text-slate-300">
                      <span className="text-slate-400">Cardio:</span> {week[selectedDay].cardio} min
                    </div>
                    <div className="rounded-xl border border-white/10 bg-slate-950/50 p-3 text-sm text-slate-200">
                      {week[selectedDay].note}
                    </div>
                  </div>
                ) : (
                  <div className="flex h-full min-h-[130px] items-center justify-center text-center">
                    <div>
                      <div className="text-3xl">🌱</div>
                      <div className="mt-2 text-sm text-slate-300">Tap a day to see your workout snapshot</div>
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="rounded-3xl border border-white/10 bg-gradient-to-br from-slate-950/40 to-emerald-950/30 p-5">
              <div className="text-xs uppercase tracking-[0.2em] text-slate-400">Motivation</div>
              <div className="mt-2 text-lg font-semibold text-slate-100 leading-snug">
                {goal ? `${goal} · ${focus}` : "Keep going, one session at a time."}
              </div>
              <p className="mt-3 text-sm text-slate-300">
                {weeklyNote || "Write your weekly reminder here."}
              </p>

              <div className="mt-4 flex items-center gap-3">
                <div className="h-12 w-12 rounded-2xl bg-emerald-400/15 border border-emerald-400/20 flex items-center justify-center text-xl">
                  🏅
                </div>
                <div>
                  <div className="text-sm font-medium text-slate-100">Consistency compounds</div>
                  <div className="text-xs text-slate-400">Your week is a story you can repeat</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function StatCard({ label, value, hint, color }) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/5 p-4 overflow-hidden relative">
      <div className={`absolute inset-0 bg-gradient-to-br ${color} opacity-10`} />
      <div className="relative">
        <div className="text-xs uppercase tracking-[0.18em] text-slate-400">{label}</div>
        <div className="mt-2 text-2xl font-bold text-slate-50">{value}</div>
        <div className="mt-1 text-xs text-slate-400">{hint}</div>
      </div>
    </div>
  );
}
